// Utilities, random helpers, PDF generator, session management
// ═══════════════════════════════════════════════════════════════

// ── Random helpers ──────────────────────────────────────────────
const R = {
  int: (min, max) => Math.floor(Math.random() * (max - min + 1)) + min,
  pick: arr => arr[Math.floor(Math.random() * arr.length)],
  shuffle: arr => {
    const a = [...arr];
    for (let i = a.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [a[i], a[j]] = [a[j], a[i]];
    }
    return a;
  },
  nonZero: (min, max) => { let v; do { v = R.int(min, max); } while (v === 0); return v; },
};

// ── GCD / LCM ───────────────────────────────────────────────────
function gcd(a, b) { return b === 0 ? Math.abs(a) : gcd(b, a % b); }
function lcm(a, b) { return Math.abs(a * b) / gcd(a, b); }

// ── Fraction helpers ─────────────────────────────────────────────
function simplify(n, d) {
  const g = gcd(Math.abs(n), Math.abs(d));
  return [n / g, d / g];
}
function fracStr(n, d) {
  if (d === 1) return String(n);
  return `${n}/${d}`;
}

// ── Choice builder ───────────────────────────────────────────────
function makeChoices(correct, wrongs) {
  const pool = [String(correct), ...wrongs.map(String)];
  const unique = [...new Set(pool)].slice(0, 4);
  while (unique.length < 4) unique.push(String(correct + unique.length * 7 + 3));
  return R.shuffle(unique);
}

// ── Answer checker ───────────────────────────────────────────────
// FIX: perbandingan jawaban sebelumnya pakai === string biasa.
// Sekarang: normalkan dulu (strip spasi, ganti koma→titik, parse numerik jika bisa).
// "0.1" vs "0.10" → sama ✓ | "0,5" vs "0.5" → sama ✓ | "1/2" vs "1/2" → sama ✓
function normalizeAnswer(raw) {
  if (raw === null || raw === undefined) return '';
  let s = String(raw).trim();

  // Ganti koma desimal gaya Indonesia ke titik
  // Hanya jika polanya angka,angka (bukan pecahan seperti "1/2")
  s = s.replace(/^(\d+),(\d+)$/, '$1.$2');

  // Strip trailing zero pada desimal: "0.10" → "0.1", "3.0" → "3"
  const asNum = parseFloat(s);
  if (!isNaN(asNum) && s.trim() !== '' && !/[a-zA-Z%]/.test(s)) {
    return String(asNum);
  }

  // Normalisasi spasi di sekitar operator untuk ekspresi aljabar:
  // "6x+ 2y" === "6x + 2y" === "6x+2y" → semua jadi "6x+2y"
  // Juga normalisasi karakter minus Unicode (−, –) ke ASCII minus (-)
  // Catatan: hanya dijalankan untuk non-numerik agar "0.10" tetap bisa di-parseFloat dulu
  s = s
    .replace(/[−–—]/g, '-')    // minus matematika → ASCII minus
    .replace(/\s*\+\s*/g, '+') // hapus spasi di sekitar +
    .replace(/\s*-\s*/g, '-')  // hapus spasi di sekitar -
    .replace(/\s*\*\s*/g, '*') // hapus spasi di sekitar *
    .replace(/\s+/g, '');       // hapus sisa spasi (misal "6 x" → "6x")

  // Coba parse ulang setelah normalisasi (tangani "0.10", "3.0", dll)
  const asNum2 = parseFloat(s);
  if (!isNaN(asNum2) && s.trim() !== '' && !/[a-zA-Z%]/.test(s)) {
    return String(asNum2);
  }

  return s.toLowerCase();
}

function checkAnswer(userInput, correctAnswer) {
  const u = normalizeAnswer(userInput);
  const c = normalizeAnswer(correctAnswer);
  if (u === '' ) return false;
  return u === c;
}

// ── Session storage helpers ──────────────────────────────────────
const Session = {
  save: (key, val) => sessionStorage.setItem('MLU_' + key, JSON.stringify(val)),
  load: (key) => {
    try { return JSON.parse(sessionStorage.getItem('MLU_' + key)); } catch { return null; }
  },
  clear: () => {
    Object.keys(sessionStorage).filter(k => k.startsWith('MLU_')).forEach(k => sessionStorage.removeItem(k));
  }
};

// ── Strip HTML untuk PDF ─────────────────────────────────────────
// FIX: jsPDF Helvetica hanya mendukung Latin-1.
// Karakter Unicode seperti − (U+2212, minus matematika) muncul sebagai tanda kutip.
// Semua simbol dikonversi ke padanan ASCII yang aman sebelum dikirim ke jsPDF.
function stripHtml(str) {
  return String(str)
    .replace(/<[^>]+>/g, '')
    .replace(/&times;/g,  'x')
    .replace(/&divide;/g, ':')
    .replace(/&minus;/g,  '-')
    .replace(/&plus;/g,   '+')
    .replace(/&lt;/g,     '<')
    .replace(/&gt;/g,     '>')
    .replace(/&amp;/g,    '&')
    .replace(/&nbsp;/g,   ' ')
    .replace(/&#(\d+);/g, (_, code) => String.fromCharCode(Number(code)))
    .replace(/[−–—]/g, '-')
    .replace(/×/g, 'x')
    .replace(/÷/g, ':')
    .replace(/\s+/g, ' ')
    .trim();
}

// ── HMAC-SHA256 Certificate Auth (via SubtleCrypto) ─────────────
// Secret key — ganti sesuai kebutuhan admin (harus sama di verifikator)
const CERT_SECRET = 'ALGEBRA';

async function generateHMAC(data) {
  const enc = new TextEncoder();
  const key = await crypto.subtle.importKey(
    'raw', enc.encode(CERT_SECRET),
    { name: 'HMAC', hash: 'SHA-256' },
    false, ['sign']
  );
  const sig = await crypto.subtle.sign('HMAC', key, enc.encode(data));
  return Array.from(new Uint8Array(sig))
    .map(b => b.toString(16).padStart(2, '0'))
    .join('').substring(0, 16).toUpperCase(); // 16 hex chars
}

// ── QR Code canvas (memerlukan qrcode-generator di halaman) ──────
function generateQRCanvas(text, size = 128) {
  try {
    const qr = qrcode(0, 'M');
    qr.addData(text);
    qr.make();
    const moduleCount = qr.getModuleCount();
    const scale = Math.floor(size / moduleCount);
    const actualSize = scale * moduleCount;
    const canvas = document.createElement('canvas');
    canvas.width = actualSize;
    canvas.height = actualSize;
    const ctx = canvas.getContext('2d');
    ctx.fillStyle = '#FFFFFF';
    ctx.fillRect(0, 0, actualSize, actualSize);
    ctx.fillStyle = '#000000';
    for (let r = 0; r < moduleCount; r++) {
      for (let c = 0; c < moduleCount; c++) {
        if (qr.isDark(r, c)) ctx.fillRect(c * scale, r * scale, scale, scale);
      }
    }
    return canvas.toDataURL('image/png');
  } catch(e) { return null; }
}

// ── PDF Generator (via jsPDF) ────────────────────────────────────
async function generatePDF({ userName, levelTitle, levelNum, score, total, questions, answers, passed }) {
  const { jsPDF } = window.jspdf;
  const doc = new jsPDF({ unit: 'mm', format: 'a4' });
  const pw = 210, ph = 297;
  const ml = 20, mr = 20, mt = 20;
  const cw = pw - ml - mr;
  const pct = Math.round((score / total) * 100);

  const COLORS = {
    dark: [15, 17, 26],
    gold: [230, 175, 46],
    green: [56, 193, 114],
    red: [239, 83, 80],
    muted: [120, 128, 160],
    white: [255, 255, 255],
    surface: [22, 24, 36],
    surface2: [30, 32, 48],
  };

  function setFill(c) { doc.setFillColor(...c); }
  function setStroke(c) { doc.setDrawColor(...c); }
  function setTxt(c) { doc.setTextColor(...c); }
  function rect(x, y, w, h, style = 'F') { doc.rect(x, y, w, h, style); }

  // ── PAGE: CERTIFICATE (if passed) ─────────────────────────────
  if (passed) {
    setFill(COLORS.dark); rect(0, 0, pw, ph);

    // Gold border ornament
    setStroke(COLORS.gold); doc.setLineWidth(0.5);
    doc.rect(10, 10, pw - 20, ph - 20);
    doc.setLineWidth(0.2);
    doc.rect(12, 12, pw - 24, ph - 24);

    // Corner decorations
    const corners = [[10,10],[pw-10,10],[10,ph-10],[pw-10,ph-10]];
    setFill(COLORS.gold);
    corners.forEach(([cx, cy]) => doc.circle(cx, cy, 2, 'F'));

    // ── Logo sekolah (di-embed sebagai base64 agar portable) ────────
    const LOGO_B64 = '';

    // Nama sekolah di tengah header
    setTxt(COLORS.gold);
    doc.setFont('helvetica', 'bold');
    doc.setFontSize(14);
    doc.text('MTS SAINS ALGEBRA', pw / 2, 21, { align: 'center' });
    doc.setFontSize(8);
    doc.setFont('helvetica', 'normal');
    setTxt(COLORS.muted);
    doc.text('PROGRAM SERTIFIKASI MATEMATIKA - MATH LEVEL UP', pw / 2, 26, { align: 'center' });
    // Garis pemisah bawah header
    setStroke(COLORS.gold); doc.setLineWidth(0.3);
    doc.line(15, 31, pw - 15, 31);

    // Logo tunggal di tengah, tepat di atas SERTIFIKAT
    // Efek lingkaran: circle putih background → gambar logo → circle emas border
    try {
      const logoSize = 36;
      const logoX = pw / 2 - logoSize / 2;
      const logoY = 46;
      const cx = pw / 2;
      const cy = logoY + logoSize / 2;
      const r = logoSize / 2;

      // 1. Lingkaran putih sebagai background (menutupi sudut kotak logo)
      doc.setFillColor(255, 255, 255);
      doc.circle(cx, cy, r, 'F');

      // 2. Gambar logo (kotak, tapi sudutnya tersembunyi di balik lingkaran putih)
      doc.addImage('data:image/jpeg;base64,' + LOGO_B64, 'JPEG', logoX, logoY, logoSize, logoSize);

      // 3. Re-draw lingkaran putih tipis di pinggir untuk menutupi sisa sudut kotak
      doc.setFillColor(255, 255, 255);
      // Segitiga menutupi pojok kiri atas
      doc.setDrawColor(255, 255, 255);
      doc.setLineWidth(2);
      // Gambar circle transparan (stroke putih tebal) untuk clip sudut
      doc.circle(cx, cy, r + 0.5, 'S');

      // 4. Border lingkaran emas
      doc.setDrawColor(...[230, 175, 46]);
      doc.setLineWidth(1.2);
      doc.circle(cx, cy, r + 0.3, 'S');

      // 5. Border lingkaran emas kedua (lebih tipis, sedikit lebih besar = double ring)
      doc.setLineWidth(0.4);
      doc.circle(cx, cy, r + 2, 'S');
    } catch(e) { /* skip jika gagal */ }

    // Judul sertifikat
    setTxt(COLORS.gold);
    doc.setFont('helvetica', 'bold');
    doc.setFontSize(22);
    doc.text('SERTIFIKAT', pw / 2, 99, { align: 'center' });

    // Divider line
    setStroke(COLORS.gold); doc.setLineWidth(0.4);
    doc.line(ml + 20, 105, pw - mr - 20, 105);

    setTxt([200, 210, 235]);
    doc.setFont('helvetica', 'normal');
    doc.setFontSize(10);
    doc.text('Sertifikat ini menyatakan bahwa', pw / 2, 119, { align: 'center' });

    // Name
    setTxt(COLORS.white);
    doc.setFont('helvetica', 'bold');
    doc.setFontSize(26);
    doc.text(userName, pw / 2, 136, { align: 'center' });

    // Underline name
    setStroke(COLORS.gold); doc.setLineWidth(0.3);
    const nw = doc.getTextWidth(userName);
    doc.line(pw / 2 - nw / 2, 139, pw / 2 + nw / 2, 139);

    setTxt([200, 210, 235]);
    doc.setFont('helvetica', 'normal');
    doc.setFontSize(10);
    doc.text('telah berhasil menyelesaikan dan LULUS pada', pw / 2, 151, { align: 'center' });

    setTxt(COLORS.gold);
    doc.setFont('helvetica', 'bold');
    doc.setFontSize(14);
    doc.text(`Level ${levelNum} - ${levelTitle}`, pw / 2, 162, { align: 'center' });

    setTxt([200, 210, 235]);
    doc.setFont('helvetica', 'normal');
    doc.setFontSize(10);
    doc.text('dengan hasil:', pw / 2, 174, { align: 'center' });

    // Score badge
    setFill(COLORS.surface2); rect(pw / 2 - 30, 178, 60, 22, 'F');
    setStroke(COLORS.gold); doc.setLineWidth(0.3); doc.rect(pw / 2 - 30, 178, 60, 22);
    setTxt(COLORS.gold);
    doc.setFont('helvetica', 'bold');
    doc.setFontSize(20);
    doc.text(`${pct}%`, pw / 2, 192, { align: 'center' });

    doc.setFontSize(9);
    setTxt(COLORS.muted);
    doc.text(`( ${score} benar dari ${total} soal )`, pw / 2, 204, { align: 'center' });

    // Date
    const now = new Date();
    const tgl = now.toLocaleDateString('id-ID', { day: 'numeric', month: 'long', year: 'numeric' });
    doc.setFontSize(9);
    setTxt([170, 178, 200]);
    doc.text(`Diterbitkan: ${tgl}`, pw / 2, 218, { align: 'center' });

    // ── QR Code HMAC Authentication ─────────────────────────────
    try {
      // Build payload: NAMA|LEVEL|TANGGAL|SKOR
      const certPayload = `${userName}|${levelNum}|${tgl}|${pct}`;
      const hmacStr = await generateHMAC(certPayload);
      const qrText = `MLU:${certPayload}|${hmacStr}`;
      const qrDataUrl = generateQRCanvas(qrText, 120);

      if (qrDataUrl) {
        // QR box (kiri bawah sertifikat)
        const qrSize = 28; // mm di PDF
        const qrX = ml + 5;
        const qrY = 228;

        // Background kotak putih untuk QR
        doc.setFillColor(255, 255, 255);
        doc.roundedRect(qrX - 2, qrY - 2, qrSize + 4, qrSize + 14, 2, 2, 'F');

        // Border emas
        doc.setDrawColor(...[230, 175, 46]);
        doc.setLineWidth(0.4);
        doc.roundedRect(qrX - 2, qrY - 2, qrSize + 4, qrSize + 14, 2, 2, 'S');

        // QR image
        doc.addImage(qrDataUrl, 'PNG', qrX, qrY, qrSize, qrSize);

        // Label
        doc.setFontSize(5.5);
        doc.setFont('helvetica', 'normal');
        doc.setTextColor(80, 80, 100);
        doc.text('SCAN TO VERIFY', qrX + qrSize / 2, qrY + qrSize + 4, { align: 'center' });
        doc.text('Auth: ' + hmacStr, qrX + qrSize / 2, qrY + qrSize + 8, { align: 'center' });

        // Keterangan kanan QR
        doc.setFontSize(6.5);
        doc.setTextColor(150, 160, 190);
        doc.text('Sertifikat ini dapat diverifikasi', qrX + qrSize + 8, qrY + 8, { align: 'left' });
        doc.text('keasliannya melalui QR code.', qrX + qrSize + 8, qrY + 13, { align: 'left' });
        doc.text('ID: ' + hmacStr, qrX + qrSize + 8, qrY + 20, { align: 'left' });
      }
    } catch(qrErr) { /* skip QR jika gagal */ }

    doc.addPage();
  }

  // ── PAGE(S): PEMBAHASAN ────────────────────────────────────────
  setFill(COLORS.dark); rect(0, 0, pw, ph);
  setFill(COLORS.surface); rect(0, 0, pw, 32);
  setTxt(COLORS.gold);
  doc.setFont('helvetica', 'bold');
  doc.setFontSize(14);
  doc.text('PEMBAHASAN SOAL', pw / 2, 14, { align: 'center' });
  setTxt(COLORS.muted);
  doc.setFont('helvetica', 'normal');
  doc.setFontSize(8);
  doc.text(`${levelTitle}  ·  ${userName}  ·  Skor: ${pct}% (${score}/${total})`, pw / 2, 23, { align: 'center' });

  let y = 40;
  const lineH = 5.5;
  const pageBottom = ph - 18;

  function checkNewPage(neededHeight = 0) {
    if (y + neededHeight > pageBottom) {
      doc.addPage();
      setFill(COLORS.dark); rect(0, 0, pw, ph);
      setFill(COLORS.surface); rect(0, 0, pw, 18);
      setTxt(COLORS.gold);
      doc.setFont('helvetica', 'bold');
      doc.setFontSize(9);
      doc.text('PEMBAHASAN — MATH LEVEL UP', pw / 2, 12, { align: 'center' });
      y = 26;
    }
  }

  questions.forEach((q, idx) => {
    const userAns = answers[idx];
    const correct = String(q.answer);

    // FIX: gunakan checkAnswer() yang toleran format, bukan === string biasa.
    // Ini memastikan "0.1" === "0.10", "0,5" === "0.5", dll.
    const isRight = checkAnswer(userAns, correct);

    // ── Estimasi tinggi total blok soal ini sebelum mulai render ──
    // Agar tidak terpotong di tengah halaman.
    const qText = stripHtml(q.text);
    doc.setFontSize(8.5);
    const qLines = doc.splitTextToSize(qText, cw - 10);
    const expText = stripHtml(q.explanation || '');
    doc.setFontSize(7.5);
    const expLines = doc.splitTextToSize(expText, cw - 12);

    // Estimasi: chip+soal + choices/isian + explanation + margin
    let estHeight = qLines.length * lineH + 2;
    if (q.type === 'pg') {
      estHeight += (q.choices || []).length * lineH;
    } else {
      estHeight += lineH * (isRight ? 1 : 2);
    }
    estHeight += expLines.length * lineH + 10;

    // Jika blok ini tidak muat di sisa halaman, pindah halaman dulu
    checkNewPage(Math.min(estHeight, 60)); // min 60mm: jangan pindah terlalu agresif

    // ── Number chip ───────────────────────────────────────────────
    const chipColor = isRight ? COLORS.green : COLORS.red;
    setFill(chipColor);
    doc.roundedRect(ml, y - 3.5, 7, 6, 1, 1, 'F');
    setTxt(COLORS.white);
    doc.setFont('helvetica', 'bold');
    doc.setFontSize(7);
    doc.text(String(idx + 1), ml + 3.5, y + 0.8, { align: 'center' });

    // ── Question text ─────────────────────────────────────────────
    setTxt([220, 225, 245]);
    doc.setFont('helvetica', 'normal');
    doc.setFontSize(8.5);
    // qLines sudah dihitung di atas
    doc.text(qLines, ml + 10, y + 0.8);
    y += qLines.length * lineH + 2;

    // ── Choices / Isian ───────────────────────────────────────────
    if (q.type === 'pg') {
      const opts = ['A', 'B', 'C', 'D'];
      (q.choices || []).forEach((ch, ci) => {
        // FIX: gunakan checkAnswer() juga untuk mencocokkan pilihan,
        // bukan === string. Penting untuk soal desimal.
        const isCorrectChoice = checkAnswer(String(ch), correct);
        const isUserChoice    = checkAnswer(String(ch), userAns);
        checkNewPage(lineH + 2);

        let bg = null;
        if (isCorrectChoice) bg = [30, 60, 40];
        else if (isUserChoice && !isCorrectChoice) bg = [60, 25, 25];

        if (bg) { setFill(bg); rect(ml + 10, y - 3, cw - 10, 6, 'F'); }

        const prefix = isCorrectChoice ? '✓' : (isUserChoice ? '✗' : ' ');
        setTxt(isCorrectChoice ? COLORS.green : isUserChoice ? COLORS.red : COLORS.muted);
        doc.setFont('helvetica', isCorrectChoice || isUserChoice ? 'bold' : 'normal');
        doc.setFontSize(8);
        // FIX: stripHtml pada teks pilihan agar simbol tidak jadi kotak kosong
        doc.text(`${prefix} ${opts[ci]}. ${stripHtml(String(ch))}`, ml + 12, y + 0.8);
        y += lineH;
      });
    } else {
      checkNewPage(lineH * 2 + 2);
      setTxt(isRight ? COLORS.green : COLORS.red);
      doc.setFont('helvetica', 'bold');
      doc.setFontSize(8);
      const ua = userAns || '(tidak dijawab)';
      doc.text(`Jawaban kamu: ${ua}`, ml + 10, y + 0.8);
      y += lineH;
      if (!isRight) {
        checkNewPage(lineH + 2);
        setTxt(COLORS.green);
        doc.text(`Jawaban benar: ${correct}`, ml + 10, y + 0.8);
        y += lineH;
      }
    }

    // ── Explanation ───────────────────────────────────────────────
    checkNewPage(expLines.length * lineH + 10);
    // FIX: hapus emoji 💡 karena jsPDF tidak bisa render emoji → jadi kotak kosong.
    // Ganti dengan teks biasa "[i]" atau prefix visual lain.
    const expLabel = 'Penjelasan: ' + expText;
    doc.setFontSize(7.5);
    const expLinesRender = doc.splitTextToSize(expLabel, cw - 12);
    setFill([20, 28, 40]); rect(ml + 10, y - 2, cw - 10, expLinesRender.length * lineH + 3, 'F');
    setTxt([150, 180, 230]);
    doc.setFont('helvetica', 'italic');
    doc.text(expLinesRender, ml + 13, y + 1.5);
    y += expLinesRender.length * lineH + 6;
  });

  // ── Page numbers ──────────────────────────────────────────────
  const totalPages = doc.getNumberOfPages();
  for (let i = 1; i <= totalPages; i++) {
    doc.setPage(i);
    setTxt(COLORS.muted);
    doc.setFont('helvetica', 'normal');
    doc.setFontSize(7);
    doc.text(`Halaman ${i} / ${totalPages}`, pw - mr, ph - 8, { align: 'right' });
  }

  const filename = `MLU_Level${levelNum}_${userName.replace(/\s+/g, '_')}.pdf`;
  doc.save(filename);
}